import java.util.Scanner;
 public class Solution {
     public static void main(String[] args) {
         Scanner sc = new Scanner(System.in);

         // Read 7 allowances (Mon to Sun)
         int monAllow = sc.nextInt();
         int tueAllow = sc.nextInt();
         int wedAllow = sc.nextInt();
         int thuAllow = sc.nextInt();
         int friAllow = sc.nextInt();
         int satAllow = sc.nextInt();
         int sunAllow = sc.nextInt();

         // Read 7 expenses (Mon to Sun)
         int monExp = sc.nextInt();
         int tueExp = sc.nextInt();
         int wedExp = sc.nextInt();
         int thuExp = sc.nextInt();
         int friExp = sc.nextInt();
         int satExp = sc.nextInt();
         int sunExp = sc.nextInt();

         // Compute totals
         int totalAllowance = monAllow + tueAllow + wedAllow + thuAllow + friAllow + satAllow + sunAllow;
         int totalExpenses = monExp + tueExp + wedExp + thuExp + friExp + satExp + sunExp;
         int savings = totalAllowance - totalExpenses;

         // Output results
         System.out.println("Total Allowance: " + totalAllowance);
         System.out.println("Total Expenses: " + totalExpenses);
         System.out.println("Weekly Savings: " + savings);

     }
 }
